
.panel-layout {
  display: grid;
  gap: 12px;
}

.panel-card {
  padding: 14px;
  border-radius: 14px;
  background: rgba(255, 250, 241, 0.78);
  border: 1px solid rgba(111, 78, 55, 0.14);
}

.overview-card {
  background: linear-gradient(180deg, rgba(68, 101, 110, 0.08), transparent 60%), rgba(255, 250, 241, 0.82);
}

.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  margin-bottom: 12px;
}

.section-title {
  font-size: 0.92rem;
  font-weight: 700;
  color: var(--c-text);
}

.pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 3px 8px;
  border-radius: 999px;
  font-size: 0.72rem;
}

.neutral {
  color: var(--c-muted);
  background: rgba(111, 78, 55, 0.06);
}

.accent {
  color: var(--c-cyan);
  background: rgba(68, 101, 110, 0.1);
}

.warn {
  color: var(--c-orange);
  background: rgba(168, 94, 50, 0.1);
}

.info-grid,
.card-grid,
.district-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.info-item,
.mini-card,
.district-card {
  padding: 12px;
  border-radius: 12px;
  background: rgba(248, 240, 225, 0.82);
  border: 1px solid rgba(111, 78, 55, 0.12);
}

.label {
  display: block;
  font-size: 0.72rem;
  color: var(--c-muted);
  margin-bottom: 4px;
}

.value {
  font-size: 0.96rem;
  font-weight: 700;
  color: var(--c-text);
}

.mini-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 8px;
  margin-bottom: 10px;
}

.mini-title {
  font-weight: 700;
  color: var(--c-text);
}

.mini-list,
.district-bars {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.mini-row,
.bar-row {
  display: flex;
  justify-content: space-between;
  gap: 10px;
  font-size: 0.76rem;
  color: var(--c-muted);
}

.tag-list {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-top: 10px;
}

.tag {
  padding: 3px 8px;
  border-radius: 999px;
  background: rgba(193, 139, 69, 0.12);
  color: var(--c-orange);
  font-size: 0.72rem;
}

.muted-tag {
  background: rgba(111, 78, 55, 0.06);
  color: var(--c-muted);
}

@media (max-width: 720px) {
  .info-grid,
  .card-grid,
  .district-grid {
    grid-template-columns: 1fr;
  }
}
