
.player-layout {
  display: grid;
  gap: 12px;
}

.panel-card {
  padding: 14px;
  border-radius: 14px;
  background: rgba(255, 250, 241, 0.78);
  border: 1px solid rgba(111, 78, 55, 0.14);
}

.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  margin-bottom: 12px;
}

.section-title {
  font-size: 0.92rem;
  font-weight: 700;
  color: var(--c-text);
}

.pill {
  padding: 3px 8px;
  border-radius: 999px;
  font-size: 0.72rem;
  background: rgba(111, 78, 55, 0.06);
  color: var(--c-muted);
}

.info-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.info-item {
  padding: 12px;
  border-radius: 12px;
  background: rgba(248, 240, 225, 0.82);
  border: 1px solid rgba(111, 78, 55, 0.12);
}

.label {
  display: block;
  font-size: 0.72rem;
  color: var(--c-muted);
  margin-bottom: 4px;
}

.value {
  display: block;
  font-size: 0.94rem;
  font-weight: 700;
  color: var(--c-text);
}

.sub {
  display: block;
  font-size: 0.76rem;
  color: var(--c-muted);
  margin-top: 2px;
}

.bar-list {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.bar-item {
  padding: 12px;
  border-radius: 12px;
  background: rgba(248, 240, 225, 0.82);
  border: 1px solid rgba(111, 78, 55, 0.12);
}

.bar-head {
  display: flex;
  justify-content: space-between;
  gap: 10px;
  font-size: 0.78rem;
  color: var(--c-muted);
  margin-bottom: 8px;
}

.bar-head strong {
  color: var(--c-text);
}

.progress-track {
  width: 100%;
  height: 8px;
  border-radius: 999px;
  overflow: hidden;
  background: rgba(111, 78, 55, 0.12);
}

.progress-fill {
  height: 100%;
  border-radius: inherit;
}

.green { background: var(--c-green); }
.orange { background: var(--c-orange); }
.red { background: var(--c-red); }
.purple { background: var(--c-purple); }

.tag-list {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.second-row {
  margin-top: 10px;
}

.tag {
  padding: 3px 8px;
  border-radius: 999px;
  background: rgba(68, 101, 110, 0.1);
  color: var(--c-cyan);
  font-size: 0.72rem;
}

.network-tag {
  background: rgba(111, 84, 125, 0.1);
  color: var(--c-purple);
}

.muted-tag {
  background: rgba(111, 78, 55, 0.06);
  color: var(--c-muted);
}

@media (max-width: 720px) {
  .info-grid,
  .bar-list {
    grid-template-columns: 1fr;
  }
}
