
.quickfeed-layout {
  display: grid;
  gap: 12px;
}

.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
}

.section-title {
  font-size: 0.98rem;
  font-family: var(--font-heading);
  font-weight: 700;
  color: var(--c-text);
}

.section-sub {
  margin-top: 2px;
  font-size: 0.76rem;
  color: var(--c-muted);
}

.section-badge {
  display: inline-flex;
  align-items: center;
  padding: 4px 10px;
  border-radius: 999px;
  font-size: 0.76rem;
  font-weight: 700;
  background: rgba(68, 101, 110, 0.1);
  color: var(--c-cyan);
  border: 1px solid rgba(68, 101, 110, 0.14);
}

.alerts-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 10px;
}

.alert-card {
  display: flex;
  flex-direction: column;
  gap: 6px;
  padding: 12px;
  border-radius: 12px;
  background: rgba(248, 240, 225, 0.82);
  border: 1px solid rgba(111, 78, 55, 0.12);
}

.feature-card {
  background: linear-gradient(180deg, rgba(193, 139, 69, 0.08), transparent 72%), rgba(248, 240, 225, 0.9);
}

.danger-card {
  background: linear-gradient(180deg, rgba(140, 48, 48, 0.08), transparent 72%), rgba(248, 240, 225, 0.9);
}

.alert-head {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  align-items: center;
}

.alert-label {
  font-size: 0.72rem;
  color: var(--c-muted);
}

.alert-title {
  font-size: 0.9rem;
  font-weight: 700;
  color: var(--c-text);
}

.alert-sub {
  font-size: 0.74rem;
  color: var(--c-muted);
  line-height: 1.45;
}

.pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 2px 8px;
  border-radius: 999px;
  font-size: 0.7rem;
  border: 1px solid rgba(111, 78, 55, 0.16);
}

.accent {
  color: var(--c-accent);
  background: rgba(143, 45, 45, 0.08);
}

.neutral {
  color: var(--c-muted);
  background: rgba(111, 78, 55, 0.06);
}

.safe {
  color: var(--c-green);
  background: rgba(87, 107, 61, 0.1);
}

.warn {
  color: var(--c-orange);
  background: rgba(168, 94, 50, 0.1);
}

.danger {
  color: var(--c-red);
  background: rgba(140, 48, 48, 0.1);
}

@media (max-width: 860px) {
  .alerts-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 520px) {
  .section-head {
    flex-direction: column;
    align-items: flex-start;
  }

  .alerts-grid {
    grid-template-columns: 1fr;
  }
}
