
.dashboard-shell {
  width: 100%;
  max-width: 980px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  background:
    radial-gradient(circle at top right, rgba(166, 70, 48, 0.12), transparent 42%),
    linear-gradient(180deg, var(--c-panel), var(--c-bg));
  border: 1px solid rgba(111, 78, 55, 0.35);
  border-radius: 18px;
  overflow: hidden;
  box-shadow: var(--shadow-panel);
}

.content-area {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 14px;
}
