
.topbar {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 14px;
  background:
    radial-gradient(circle at top right, rgba(143, 45, 45, 0.14), transparent 46%),
    linear-gradient(180deg, rgba(72, 45, 24, 0.92), rgba(72, 45, 24, 0.82));
  border-bottom: 1px solid rgba(255, 244, 230, 0.12);
}

.topbar-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.brand {
  display: flex;
  align-items: center;
  gap: 10px;
  min-width: 0;
}

.icon {
  font-size: 1.4rem;
}

.title {
  color: #fff8ef;
  font-family: var(--font-heading);
  font-size: 1.08rem;
  font-weight: 700;
  letter-spacing: 0.04em;
}

.subtitle {
  color: rgba(255, 244, 230, 0.72);
  font-size: 0.76rem;
  margin-top: 2px;
}

.meta-box {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: 7px 12px;
  border-radius: 999px;
  background: rgba(255, 248, 239, 0.08);
  border: 1px solid rgba(255, 244, 230, 0.14);
  color: #fff8ef;
  white-space: nowrap;
  text-align: right;
}

.meta-main {
  font-size: 0.8rem;
  font-weight: 700;
}

.meta-sub {
  font-size: 0.72rem;
  color: rgba(255, 244, 230, 0.7);
}

.tabs {
  display: flex;
  align-items: stretch;
  background: rgba(255, 248, 239, 0.08);
  border: 1px solid rgba(255, 244, 230, 0.14);
  border-radius: 12px;
  overflow-x: auto;
  scrollbar-width: none;
}

.tabs::-webkit-scrollbar {
  display: none;
}

.tab-button {
  appearance: none;
  border: none;
  background: transparent;
  color: rgba(255, 244, 230, 0.7);
  padding: 10px 18px;
  min-width: 100px;
  cursor: pointer;
  letter-spacing: 0.05em;
  border-right: 1px solid rgba(255, 244, 230, 0.08);
  transition: 0.2s ease;
  flex: 1 0 auto;
}

.tab-button:last-child {
  border-right: none;
}

.tab-button:hover {
  color: #fff8ef;
  background: rgba(255, 248, 239, 0.08);
}

.tab-button.active {
  color: #fff8ef;
  background: linear-gradient(180deg, rgba(193, 139, 69, 0.35), rgba(143, 45, 45, 0.18));
  box-shadow: inset 0 -2px 0 rgba(255, 248, 239, 0.5);
}

@media (max-width: 640px) {
  .topbar-head {
    flex-direction: column;
    align-items: flex-start;
  }

  .meta-box {
    align-self: stretch;
    text-align: left;
    border-radius: 12px;
  }
}
