
.world-layout {
  display: grid;
  gap: 12px;
}

.panel-card,
.task-section {
  padding: 14px;
  background: rgba(255, 250, 241, 0.72);
  border: 1px solid rgba(111, 78, 55, 0.16);
  border-radius: 14px;
}

.hero-card {
  background: linear-gradient(180deg, rgba(193, 139, 69, 0.08), transparent 60%), rgba(255, 250, 241, 0.82);
}

.world-bulletin-card {
  overflow: hidden;
}

.head-row,
.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  margin-bottom: 12px;
}

.section-title {
  font-size: 0.98rem;
  font-family: var(--font-heading);
  font-weight: 700;
  color: var(--c-text);
}

.section-sub {
  font-size: 0.76rem;
  color: var(--c-muted);
  margin-top: 2px;
}

.stage-pill,
.section-badge {
  display: inline-flex;
  align-items: center;
  padding: 4px 10px;
  border-radius: 999px;
  font-size: 0.76rem;
  font-weight: 700;
}

.stage-pill {
  background: rgba(143, 45, 45, 0.1);
  color: var(--c-accent);
  border: 1px solid rgba(143, 45, 45, 0.18);
}

.section-badge {
  background: rgba(68, 101, 110, 0.1);
  color: var(--c-cyan);
  border: 1px solid rgba(68, 101, 110, 0.14);
}

.meta-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 10px;
}

.meta-item {
  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 12px;
  border-radius: 12px;
  background: rgba(248, 240, 225, 0.82);
  border: 1px solid rgba(111, 78, 55, 0.12);
}

.focus-item {
  min-width: 0;
}

.meta-label {
  font-size: 0.72rem;
  color: var(--c-muted);
}

.meta-value {
  font-size: 0.96rem;
  font-weight: 700;
  color: var(--c-text);
}

.meta-sub {
  font-size: 0.76rem;
  color: var(--c-muted);
}

.tag-list {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.tag {
  display: inline-flex;
  align-items: center;
  padding: 3px 8px;
  border-radius: 999px;
  background: rgba(68, 101, 110, 0.12);
  color: var(--c-cyan);
  font-size: 0.72rem;
}

.muted-tag {
  color: var(--c-muted);
  background: rgba(111, 78, 55, 0.06);
}

.task-row {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 10px;
}

.task-card {
  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 12px;
  border-radius: 12px;
  background: rgba(245, 232, 212, 0.86);
  border-left: 4px solid rgba(193, 139, 69, 0.8);
}

.task-name {
  font-size: 0.82rem;
  font-weight: 700;
  color: var(--c-text);
}

.task-desc {
  font-size: 0.75rem;
  color: var(--c-muted);
  line-height: 1.45;
}

@media (max-width: 720px) {
  .meta-grid {
    grid-template-columns: 1fr;
  }

  .head-row,
  .section-head {
    flex-direction: column;
    align-items: flex-start;
  }
}
